/**
 * @returns {object | undefined} The language selected in `data.language`,
 * falling back to English, then to any loaded language; undefined only
 * when none are loaded.
 */
function activeLanguage() {
	return (
		languages[data.language] || languages.en || Object.values(languages)[0]
	);
}

/**
 * Looks up a translation in the active language.
 * @param {string} key Translation key.
 * @returns {string | string[]} The translated value (the `encouragement`
 * key holds an array of phrases), or the key itself when missing.
 */
function t(key) {
	return activeLanguage()?.translations?.[key] ?? key;
}

/** Rebuilds the language selector's options from {@link languages}. */
function populateLanguageSelect() {
	$("#languageSelect").replaceChildren(
		...Object.values(languages).map((language) => {
			const option = document.createElement("option");
			option.value = language.code;
			option.textContent = language.name;
			return option;
		}),
	);
}

// ---- src/wakelock.js ----
/** Currently held WakeLockSentinel, when a screen lock is active. */
let sentinel = null;
/**
 * Whether a lock *should* be held right now, independently of the async
 * request in flight — so a session that ends while the request is still
 * pending doesn't strand an active lock afterwards.
 */
let wanted = false;
let watchingVisibility = false;

/**
 * Requests a screen wake lock and stores it as the active sentinel,
 * replacing any previous one. Rechecks {@link wanted} after the await so a
 * lock granted after the session already ended is released immediately
 * rather than stranded. The granted lock clears itself from
 * {@link sentinel} when released, and re-requests right away if the
 * browser dropped it while the page was still visible (battery saver, OS
 * policy); a release while hidden is left to the visibility watcher.
 */
async function acquire() {
	try {
		const lock = await navigator.wakeLock.request("screen");
		if (!wanted) {
			lock.release().catch(() => {});
			return;
		}
		sentinel?.release().catch(() => {});
		sentinel = lock;
		lock.addEventListener("release", () => {
			// Only react when the browser dropped the lock we still consider
			// current: our own release and replacement paths manage sentinel
			// themselves, and re-requesting for a replaced lock would loop.
			if (sentinel !== lock) return;
			sentinel = null;
			if (wanted && document.visibilityState === "visible") acquire();
		});
	} catch {
		/* Dimming stays the browser's call; play continues fine without it. */
	}
}

/**
 * The browser releases the lock on its own whenever the page stops being
 * visible (switching apps, locking the device). This installs, at most
 * once, the listener that re-requests it when the page becomes visible
 * again while a lock is still wanted.
 */
function watchVisibility() {
	if (watchingVisibility) return;
	watchingVisibility = true;
	document.addEventListener("visibilitychange", () => {
		if (document.visibilityState === "visible" && wanted) acquire();
	});
}

/**
 * Keeps the screen awake from now on, so the tablet doesn't dim and lock on
 * a toddler who is just watching the effects without touching anything.
 * Entirely optional: no-op on browsers without the Wake Lock API, and when
 * the request is denied (battery saver, permissions policy) everything
 * silently behaves exactly as before.
 */
function keepScreenAwake() {
	if (!("wakeLock" in navigator)) return;
	wanted = true;
	watchVisibility();
	acquire();
}

/**
 * Stops keeping the screen awake: releases the held lock and flags any
 * still-pending request to discard its result.
 */
function releaseWakeLock() {
	wanted = false;
	sentinel?.release().catch(() => {});
	sentinel = null;
}

// ---- src/game.js ----
/**
 * @param {number} seconds Seconds to format; negatives clamp to zero.
 * @returns {string} MM:SS with zero-padded minutes and seconds.
 */
function formatTimer(seconds) {
	const safe = Math.max(0, Math.floor(seconds));
	return `${String(Math.floor(safe / 60)).padStart(2, "0")}:${String(safe % 60).padStart(2, "0")}`;
}

/**
 * Picks the big character shown on the key orb: "●" for space, the
 * uppercased character for printable keys, a symbol for known special keys,
 * the key's own name when it starts with "F" (function keys), and "✦" for
 * anything unrecognized.
 * @param {KeyboardEvent} event
 * @returns {string}
 */
function displayKey(event) {
	if (event.key === " ") return "●";
	if (event.key.length === 1) return event.key.toUpperCase();
	const labels = {
		Enter: "↵",
		Backspace: "←",
		Tab: "↹",
		ArrowUp: "↑",
		ArrowDown: "↓",
		ArrowLeft: "←",
		ArrowRight: "→",
		Shift: "⇧",
		Control: "⌃",
		Alt: "⌥",
		Meta: "⌘",
		CapsLock: "⇪",
		Escape: "⎋",
		Delete: "⌦",
		Insert: "↳",
		Home: "↖",
		End: "↘",
		PageUp: "⇞",
		PageDown: "⇟",
		ContextMenu: "☰",
		ScrollLock: "⇳",
		NumLock: "⇭",
		Pause: "Ⅱ",
		PrintScreen: "▣",
	};
	return labels[event.key] || (event.key.startsWith("F") ? event.key : "✦");
}

/**
 * Label shown under the orb: the translated word for space, otherwise the
 * same symbol as {@link displayKey}.
 * @param {KeyboardEvent} event
 * @returns {string}
 */
function keyName(event) {
	if (event.key === " ") return t("space");
	return displayKey(event);
}

/**
 * Refreshes all lifetime and session stat elements from {@link data} and
 * {@link state}, including the most-pressed key ("—" before any press).
 */
function updateStats() {
	const keyEntries = Object.entries(data.keyCounts || {});
	const favourite = keyEntries.sort((a, b) => b[1] - a[1])[0]?.[0] || "—";
	$("#totalPresses").textContent = data.totalPresses.toLocaleString();
	$("#totalMinutes").textContent = `${Math.floor(data.totalSeconds / 60)} min`;
	$("#totalUnique").textContent = data.uniqueKeys.length;
	$("#bestSpeed").textContent = data.bestSpeed;
	$("#favoriteKey").textContent = favourite;
	$("#sessionPresses").textContent = state.sessionPresses;
	$("#sessionStreak").textContent = state.bestStreak;
}

/** Renders the current streak count with its singular/plural label. */
function updateStreak() {
	const word = state.streak === 1 ? t("sequence") : t("sequences");
	$("#streakText").textContent = `${state.streak} ${word}`;
}

/**
 * Zeroes all session counters, stamps the session start time, and returns
 * the orb, key label, and encouragement line to their idle text.
 */
function resetSession() {
	state.sessionPresses = 0;
	state.sessionKeys = new Set();
	state.streak = 0;
	state.bestStreak = 0;
	state.lastKeyTime = 0;
	state.activePointers.clear();
	state.startedAt = Date.now();
	state.elapsedBeforePause = 0;
	state.paused = false;
	$("#keyOrb").textContent = "?";
	$("#keyName").textContent = t("letsPlay");
	$("#encouragement").textContent = "";
	updateStreak();
	updateStats();
}

/**
 * Total seconds elapsed in the current session: time banked from earlier,
 * non-paused segments ({@link state.elapsedBeforePause}) plus the current
 * segment, if one is running. Reading this instead of `state.startedAt`
 * directly is what lets a pause stop the clock without losing track of how
 * much play already happened.
 * @returns {number}
 */
function currentElapsedSeconds() {
	const activeSegment = state.paused
		? 0
		: (Date.now() - state.startedAt) / 1000;
	return state.elapsedBeforePause + activeSegment;
}

/**
 * Enables or disables the top-bar language selector to match the parent
 * gate. While the gate stands (setting on, session running, not paused), a
 * mid-play tap on the select would pop the browser's native dropdown over
 * the game — and a hold gesture can't guard a `<select>`, so disabling it
 * is what closes that last ungated top-bar control. It comes back the
 * moment the gate drops: welcome screen, panel open, or session over.
 */
function updateParentGateLocks() {
	$("#languageSelect").disabled =
		data.parentGate && state.playing && !state.paused;
}

/**
 * Starts a play session (no-op if one is already running): resets session
 * state, keeps the screen awake, swaps the welcome card for the key stage,
 * and begins the 500 ms timer tick.
 */
function startGame() {
	if (state.playing) return;
	resetSession();
	state.playing = true;
	keepScreenAwake();
	updateParentGateLocks();
	$("#welcomeCard").classList.add("hidden");
	$("#keyStage").classList.remove("hidden");
	$("#sessionChip").classList.remove("hidden");
	$("#bottomPrompt").classList.add("hidden");
	tick();
	state.timerId = window.setInterval(tick, 500);
}

/**
 * Timer update: counts up ("+MM:SS") in free-play mode (duration 0),
 * otherwise counts down and ends the game when time runs out. A no-op while
 * paused, though in practice {@link pauseSession} already stops the interval
 * that would call this.
 */
function tick() {
	if (!state.playing || state.paused) return;
	const elapsed = currentElapsedSeconds();
	if (Number(data.duration) === 0) {
		$("#timer").textContent = `+${formatTimer(elapsed)}`;
		return;
	}
	const remaining = Number(data.duration) * 60 - elapsed;
	$("#timer").textContent = formatTimer(remaining);
	if (remaining <= 0) endGame();
}

/**
 * Pauses the running clock (no-op if idle or already paused): banks the
 * elapsed time so far into {@link state.elapsedBeforePause} and stops the
 * tick interval, freezing the displayed timer. Meant for whenever the
 * parent's attention — and the settings/stats panel — is open instead of the
 * play area, so a timed session doesn't silently drain in the background.
 */
function pauseSession() {
	if (!state.playing || state.paused) return;
	state.elapsedBeforePause = currentElapsedSeconds();
	state.paused = true;
	clearInterval(state.timerId);
	updateParentGateLocks();
}

/**
 * Resumes a paused clock (no-op if idle or not paused): restarts the active
 * segment from now, re-renders the timer immediately, and restarts the tick
 * interval.
 */
function resumeSession() {
	if (!state.playing || !state.paused) return;
	state.paused = false;
	state.startedAt = Date.now();
	updateParentGateLocks();
	tick();
	state.timerId = window.setInterval(tick, 500);
}

/**
 * Ends the session (no-op when idle): releases the screen wake lock, folds
 * elapsed time (minimum one second) and best presses-per-minute into the
 * lifetime stats, persists them, restores the welcome screen, and opens the
 * end-of-session dialog.
 */
function endGame() {
	if (!state.playing) return;
	const elapsed = Math.max(1, Math.round(currentElapsedSeconds()));
	state.playing = false;
	state.paused = false;
	state.activePointers.clear();
	clearInterval(state.timerId);
	releaseWakeLock();
	updateParentGateLocks();
	data.totalSeconds += elapsed;
	data.bestSpeed = Math.max(
		data.bestSpeed,
		Math.round((state.sessionPresses / elapsed) * 60),
	);
	saveData();
	updateStats();
	$("#keyStage").classList.add("hidden");
	$("#sessionChip").classList.add("hidden");
	$("#welcomeCard").classList.remove("hidden");
	$("#bottomPrompt").classList.remove("hidden");
	$("#endPresses").textContent = state.sessionPresses;
	$("#endUnique").textContent = state.sessionKeys.size;
	$("#endStreak").textContent = state.bestStreak;
	$("#endDialog").showModal();
}

/**
 * Global keydown handler; inert until languages are loaded and while the
 * side panel is open. Suppresses the browser default for keys that would
 * scroll or move focus (Tab, space, arrows, Alt, Escape), then feeds the
 * press to {@link triggerInteraction} with feedback (sound and/or
 * vibration, each per its own setting).
 * @param {KeyboardEvent} event
 */
function pressKey(event) {
	if (Object.keys(languages).length === 0) return;
	// The open side panel takes the keyboard with it: keys belong to the
	// parent navigating the panel, not to the game — no effects or stats
	// spawning behind the scrim (including from the key repeats of an
	// Enter/Space still held after passing the parent gate), and no
	// preventDefault below stealing Tab from the panel's own controls.
	if (state.paused || $("#sidePanel").classList.contains("open")) return;
	if (
		event.key === "Tab" ||
		event.key === " " ||
		event.key.startsWith("Arrow") ||
		["Alt", "Escape"].includes(event.key)
	)
		event.preventDefault();
	triggerInteraction(displayKey(event), keyName(event), event, {
		feedback: true,
	});
}

/**
 * Registers one interaction and plays all of its feedback: starts a session
 * if needed, updates streaks (presses under 1.6 s apart chain) and per-key
 * counters, shows the key with a random encouragement phrase, fires the
 * visual effects, optionally plays a tone, and persists. Every interaction
 * — including Super Smash — goes through here, so stats, streak, and
 * persistence stay in one place instead of each caller tracking its own
 * subset of the bookkeeping.
 * @param {string} displayed Character shown on the orb and tracked in stats.
 * @param {string} label Text for the key-name line.
 * @param {{clientX?: number, clientY?: number}} point Effect origin for
 * pointer interactions; keyboard interactions use a random point instead.
 * @param {object} [options]
 * @param {boolean} [options.feedback=false] Discrete interaction (a keypress
 * or tap, not a mouse-trail move): plays a tone and/or vibrates, each still
 * independently gated by its own setting (`data.sound`, `data.vibration`).
 * @param {boolean} [options.pointer=false] Pointer interaction: draw a trail
 * at `point` and skip the sparkle/letter burst unless `burst` is set.
 * @param {boolean} [options.burst=false] Fire the sparkle/letter burst even
 * for a pointer interaction.
 * @param {boolean} [options.superSmash=false] A whole-hand slap: replaces
 * the usual sparkle/theme/letter effects with {@link makeSuperSmash}'s
 * screen-wide burst, and the usual single tone/buzz with a bigger pattern.
 */
function triggerInteraction(
	displayed,
	label,
	point,
	{ feedback = false, pointer = false, burst = false, superSmash = false } = {},
) {
	if (!state.playing) startGame();
	const effectPoint = pointer ? point : randomEffectPoint();
	const now = Date.now();
	state.streak = now - state.lastKeyTime < 1600 ? state.streak + 1 : 1;
	state.bestStreak = Math.max(state.bestStreak, state.streak);
	state.lastKeyTime = now;
	state.sessionPresses++;
	state.sessionKeys.add(displayed);
	data.totalPresses++;
	data.keyCounts[displayed] = (data.keyCounts[displayed] || 0) + 1;
	if (!data.uniqueKeys.includes(displayed)) data.uniqueKeys.push(displayed);
	$("#keyOrb").textContent = displayed;
	$("#keyName").textContent = label;
	$("#encouragement").textContent =
		t("encouragement")[Math.floor(Math.random() * t("encouragement").length)];
	const orb = $("#keyOrb");
	orb.classList.remove("bounce");
	void orb.offsetWidth;
	orb.classList.add("bounce");
	if (superSmash) {
		makeSuperSmash(effectPoint);
	} else {
		const points = kaleidoscopePoints(effectPoint);
		if (pointer)
			for (const kaleidoscopePoint of points)
				makePointerTrail(kaleidoscopePoint);
		if (!pointer || burst) {
			for (const kaleidoscopePoint of points) makeSparkles(kaleidoscopePoint);
			makeLetterTrail(displayed);
		}
		for (const kaleidoscopePoint of points)
			makeThemeMechanic(kaleidoscopePoint);
	}
	animateBackground();
	updateStreak();
	updateStats();
	if (feedback && data.sound) superSmash ? playSuperTone() : playTone();
	if (feedback && data.vibration)
		vibrate(superSmash ? SUPER_SMASH_PATTERN : 15);
	saveData();
}

/** Vibration pattern for Super Smash: five short, evenly-spaced pulses. */
const SUPER_SMASH_PATTERN = [40, 40, 40, 40, 40];

/**
 * Fires a short haptic pulse, or a custom pattern. A no-op wherever the
 * Vibration API doesn't exist (iOS Safari, most desktop browsers) or has no
 * hardware to act on.
 * @param {number | number[]} [pattern=15]
 */
function vibrate(pattern = 15) {
	navigator.vibrate?.(pattern);
}

/** Super Smash's bigger sound: three quick tones instead of one. */
function playSuperTone() {
	playTone();
	setTimeout(playTone, 80);
	setTimeout(playTone, 160);
}

/**
 * Points to fire a point-anchored effect at: just `point` when kaleidoscope
 * mode is off, otherwise `point` plus its mirror images across #playArea's
 * centre. Offsets are normalized to the play area's half-width/half-height
 * before the axis-swapping diagonal reflections, so on a wide screen every
 * mirrored point still lands inside the play area instead of past its top
 * or bottom edge. The reflection count scales down as {@link state.streak}
 * climbs (8 → 4 → 2) so a fast multi-key smash doesn't multiply an
 * already-fast pace of particles on top of itself — a single deliberate
 * press gets the full symmetry, and even mid-smash every burst keeps a
 * visible mirrored twin rather than the mode silently switching off.
 * @param {{clientX?: number, clientY?: number}} point
 * @returns {{clientX?: number, clientY?: number}[]}
 */
function kaleidoscopePoints(point) {
	if (
		!data.kaleidoscope ||
		!Number.isFinite(point.clientX) ||
		!Number.isFinite(point.clientY)
	)
		return [point];
	const reflections = state.streak >= 8 ? 2 : state.streak >= 4 ? 4 : 8;
	const rect = $("#playArea").getBoundingClientRect();
	// A zero-sized rect (mid-layout, hidden) would turn the normalized
	// offsets below into Infinity/NaN coordinates.
	if (rect.width <= 0 || rect.height <= 0) return [point];
	const cx = rect.left + rect.width / 2;
	const cy = rect.top + rect.height / 2;
	const nx = (point.clientX - cx) / (rect.width / 2);
	const ny = (point.clientY - cy) / (rect.height / 2);
	const offsets =
		reflections === 2
			? [
					[nx, ny],
					[-nx, -ny],
				]
			: [
					[nx, ny],
					[-nx, ny],
					[nx, -ny],
					[-nx, -ny],
				];
	if (reflections === 8)
		offsets.push([ny, nx], [-ny, nx], [ny, -nx], [-ny, -nx]);
	return offsets.map(([ox, oy]) => ({
		clientX: cx + (ox * rect.width) / 2,
		clientY: cy + (oy * rect.height) / 2,
	}));
}

/**
 * @returns {{clientX: number, clientY: number}} Random viewport point,
 * padded away from the edges and top so effects spawn in comfortable view.
 */
function randomEffectPoint() {
	const horizontalPadding = Math.min(80, window.innerWidth * 0.12);
	const topPadding = Math.min(150, window.innerHeight * 0.2);
	return {
		clientX:
			horizontalPadding +
			Math.random() * Math.max(1, window.innerWidth - horizontalPadding * 2),
		clientY:
			topPadding +
			Math.random() * Math.max(1, window.innerHeight - topPadding - 65),
	};
}

/** Simultaneous touches that trigger Super Smash instead of an ordinary tap. */
const SUPER_SMASH_TOUCH_THRESHOLD = 4;
/**
 * "Key" a Super Smash is tracked under in stats (favourite key, unique
 * keys). It isn't a real key, so it stays visually and semantically
 * distinct from any theme icon a normal tap might display.
 */
const SUPER_SMASH_KEY = "✋";

/**
 * Pointer handler for the play area; inert until languages are loaded, a
 * session is running, and the target is not a control. Interactions display
 * a random icon from the current theme: taps and clicks (pointerdown) act
 * like a full keypress with sound, while mouse movement only leaves a
 * trail, throttled to one icon per 160 ms.
 * @param {PointerEvent} event
 */
function pressPointer(event) {
	if (
		Object.keys(languages).length === 0 ||
		event.target.closest("button, select, input, label")
	)
		return;
	if (!state.playing) return;

	if (event.type === "pointerdown") {
		state.activePointers.add(event.pointerId);
		if (state.activePointers.size >= SUPER_SMASH_TOUCH_THRESHOLD) {
			state.activePointers.clear();
			// A 4-finger slap is exactly the gesture browsers read as
			// pinch-zoom or a scroll; ordinary taps below already call this
			// later in the function, but this branch returns before reaching
			// it, so it needs its own call.
			event.preventDefault();
			// Goes through triggerInteraction like any other press — not a
			// direct makeSuperSmash() call — so the touch that crosses the
			// threshold still counts toward stats, streak, and persistence
			// instead of vanishing from them.
			triggerInteraction(SUPER_SMASH_KEY, SUPER_SMASH_KEY, event, {
				pointer: true,
				feedback: true,
				superSmash: true,
			});
			return;
		}
	}

	const isMouseTrail =
		event.type === "pointermove" && event.pointerType === "mouse";
	if (event.type === "pointermove" && !isMouseTrail) return;
	const now = Date.now();
	if (isMouseTrail && now - state.lastPointerTime < 160) return;
	state.lastPointerTime = now;
	event.preventDefault();
	const icons = themeIcons[data.theme];
	const displayed = icons[Math.floor(Math.random() * icons.length)];
	triggerInteraction(displayed, displayed, event, {
		pointer: true,
		burst: event.type === "pointerdown",
		feedback: event.type === "pointerdown",
	});
}

/**
 * Removes a pointer from the active pointers set when it leaves the screen.
 * @param {PointerEvent} event
 */
function releasePointer(event) {
	state.activePointers.delete(event.pointerId);
}

// ---- src/pwa.js ----
/**
 * Hands the caller a function that tells `worker` to stop waiting and
 * activate; does nothing when no callback was provided.
 * @param {ServiceWorker} worker Installed worker waiting to activate.
 * @param {(applyUpdate: () => void) => void} [onUpdateReady]
 */
function notifyUpdate(worker, onUpdateReady) {
	if (typeof onUpdateReady !== "function") return;
	onUpdateReady(() => worker.postMessage("SKIP_WAITING"));
}

/** localStorage key remembering that the iOS install tip was dismissed. */
const IOS_TIP_DISMISSED_KEY = "magic-smash-ios-tip-dismissed";

/** @returns {boolean} Whether this is an iOS or iPadOS device. */
function isIosDevice() {
	const ua = navigator.userAgent;
	if (/iPad|iPhone|iPod/.test(ua)) return true;
	// iPadOS 13+ identifies as "MacIntel" by default; touch support is the tell.
	return navigator.platform === "MacIntel" && navigator.maxTouchPoints > 1;
}

/** @returns {boolean} Whether the app runs installed (standalone display mode). */
function isRunningStandalone() {
	return (
		window.navigator.standalone === true ||
		window.matchMedia("(display-mode: standalone)").matches
	);
}

/**
 * @returns {boolean} Whether to show the iOS install tip: only on an iOS
 * device, not under file://, not already installed, and not previously
 * dismissed.
 */
function shouldShowIosInstallTip() {
	if (window.location.protocol === "file:") return false;
	if (!isIosDevice() || isRunningStandalone()) return false;
	try {
		return localStorage.getItem(IOS_TIP_DISMISSED_KEY) !== "true";
	} catch {
		// Some browsers (e.g. Safari private mode, storage fully disabled) can
		// throw on any localStorage access. This runs during startup, so a
		// thrown error here must not stop the rest of the app from booting.
		return false;
	}
}

/** Remembers that the user dismissed the iOS install tip. */
function dismissIosInstallTip() {
	try {
		localStorage.setItem(IOS_TIP_DISMISSED_KEY, "true");
	} catch {
		/* Dismissing is best-effort; a full storage quota shouldn't block it. */
	}
}

/**
 * Injects the manifest `<link>` at runtime. Chrome fetches a
 * `<link rel="manifest">` as soon as it's parsed, before any JS runs — and
 * that fetch is blocked under file:// the same way ES module imports were.
 * A static `<link>` in the HTML has no way to opt out, so the manifest is
 * linked here instead, only when it can actually be fetched.
 */
function linkManifest() {
	if (window.location.protocol === "file:") return;
	const link = document.createElement("link");
	link.rel = "manifest";
	link.href = "manifest.webmanifest";
	document.head.appendChild(link);
}

/**
 * Registers ./sw.js once the page loads; no-op without service worker
 * support or under file://. Reloads the page (once) when a new worker takes
 * control. Both an already-waiting worker and one installed later surface
 * through `onUpdateReady`.
 * @param {(applyUpdate: () => void) => void} [onUpdateReady] Called when an
 * updated worker is ready; receives a function that activates it.
 */
function registerServiceWorker(onUpdateReady) {
	if (!("serviceWorker" in navigator) || window.location.protocol === "file:")
		return;

	let reloading = false;
	navigator.serviceWorker.addEventListener("controllerchange", () => {
		if (reloading) return;
		reloading = true;
		window.location.reload();
	});

	window.addEventListener("load", () => {
		navigator.serviceWorker
			.register("./sw.js")
			.then((registration) => {
				if (registration.waiting)
					notifyUpdate(registration.waiting, onUpdateReady);
				registration.addEventListener("updatefound", () => {
					const newWorker = registration.installing;
					if (!newWorker) return;
					newWorker.addEventListener("statechange", () => {
						const isUpdate =
							newWorker.state === "installed" &&
							navigator.serviceWorker.controller;
						if (isUpdate) notifyUpdate(newWorker, onUpdateReady);
					});
				});
			})
			.catch(() => {
				/* Installing as an app is optional; ignore registration failures. */
			});
	});
}

// ---- src/ui.js ----
const KEY_BOUNCE_DURATION_MS = 340;
/** How long the panel buttons must be held to pass the parent gate. */
const PARENT_GATE_HOLD_MS = 2000;

/** Exposes JS-owned animation timing to CSS via custom properties on the root element. */
function applyAnimationSettings() {
	document.documentElement.style.setProperty(
		"--key-bounce-duration-ms",
		`${KEY_BOUNCE_DURATION_MS}ms`,
	);
	document.documentElement.style.setProperty(
		"--parent-gate-hold-ms",
		`${PARENT_GATE_HOLD_MS}ms`,
	);
}

/**
 * Switches the UI language (no-op for unknown codes): sets the document
 * language (mapping the registry's "pt-br" to the standard "pt-BR" tag),
 * retranslates every `[data-i18n]` element (`welcomeTitle` as HTML, the
 * rest as text), refreshes labels that embed translated words, and
 * persists.
 * @param {string} language Language code from the loaded registry.
 */
function setLanguage(language) {
	if (!languages[language]) return;
	data.language = language;
	document.documentElement.lang = language === "pt-br" ? "pt-BR" : language;
	$("#languageSelect").value = language;
	$$("[data-i18n]").forEach((element) => {
		const key = element.dataset.i18n;
		if (key === "welcomeTitle") element.innerHTML = t(key);
		else element.textContent = t(key);
	});
	const profile = data.profile || t("unnamed");
	$("#profileName").textContent = profile;
	$("#childName").placeholder = t("unnamed");
	updateThemeName();
	updateColorMode();
	updateStreak();
	updateSound();
	updateStats();
	saveData();
}

/**
 * Applies a theme (no-op for unknown ids): sets it on the body's `data-theme`,
 * highlights its picker button, updates the theme-name labels, rebuilds the
 * magic background, and persists.
 * @param {string} theme Theme id from {@link themeIcons}.
 */
function setTheme(theme) {
	if (!themeIcons[theme]) return;
	data.theme = theme;
	document.body.dataset.theme = theme;
	$$("[data-theme-choice]").forEach((button) => {
		button.classList.toggle("active", button.dataset.themeChoice === theme);
	});
	updateThemeName();
	createMagicBackground();
	saveData();
}

/** Shows the active theme's translated name in the settings panel and quick chip. */
function updateThemeName() {
	const selectedThemeName = t(themeNames[data.theme]);
	$("#themeName").textContent = selectedThemeName;
	$("#quickThemeName").textContent = selectedThemeName;
}

/**
 * Sets the color mode and persists it; anything other than "dark" means light.
 * @param {string} mode
 */
function setColorMode(mode) {
	data.colorMode = mode === "dark" ? "dark" : "light";
	document.body.dataset.mode = data.colorMode;
	updateColorMode();
	saveData();
}

/** Highlights the picker button matching the current color mode. */
function updateColorMode() {
	$$("[data-mode-choice]").forEach((button) => {
		button.classList.toggle(
			"active",
			button.dataset.modeChoice === data.colorMode,
		);
	});
}

/**
 * Maps the letter-size setting (0 small, 2 large, otherwise default) onto
 * body classes and syncs the slider position.
 */
function updateLetterSize() {
	document.body.classList.toggle(
		"small-letters",
		Number(data.letterSize) === 0,
	);
	document.body.classList.toggle(
		"large-letters",
		Number(data.letterSize) === 2,
	);
	$("#letterSize").value = data.letterSize;
}

/** Syncs every duration select with the stored session duration. */
function updateDuration() {
	$$("[data-duration-select]").forEach((select) => {
		select.value = data.duration;
	});
}

/** Syncs the sound toggles. */
function updateSound() {
	$$("[data-sound-toggle]").forEach((toggle) => {
		toggle.checked = data.sound;
	});
}

/** Syncs the vibration toggles. */
function updateVibration() {
	$$("[data-vibration-toggle]").forEach((toggle) => {
		toggle.checked = data.vibration;
	});
}

/** Syncs the kaleidoscope toggle. */
function updateKaleidoscope() {
	$$("[data-kaleidoscope-toggle]").forEach((toggle) => {
		toggle.checked = data.kaleidoscope;
	});
}

/** Syncs the parent gate toggle. */
function updateParentGate() {
	$$("[data-parent-gate-toggle]").forEach((toggle) => {
		toggle.checked = data.parentGate;
	});
}

let gateHintTimerId = null;

/**
 * Briefly shows the "hold to open" hint next to the panel buttons, so a
 * parent whose tap was just blocked by the gate learns the gesture instead
 * of assuming the buttons are broken. Repeated taps restart the timer.
 */
function showParentGateHint() {
	const hint = $("#gateHint");
	hint.classList.remove("hidden");
	clearTimeout(gateHintTimerId);
	gateHintTimerId = window.setTimeout(() => hint.classList.add("hidden"), 1600);
}

/** Shows the end-session button only while a session is running. */
function updateEndSessionButton() {
	$("#endSessionButton").classList.toggle("hidden", !state.playing);
}

/**
 * Opens the side panel on either the settings or the stats view, with
 * matching title and eyebrow text, freshly rendered stats, and focus moved
 * to the close button. Pauses a running session's clock — the parent's
 * attention is here now, not on the play area, so a timed session shouldn't
 * silently drain in the background while they look around.
 * @param {string} type `"settings"` for settings; anything else shows stats.
 */
function openPanel(type) {
	const isSettings = type === "settings";
	$("#settingsPanel").classList.toggle("hidden", !isSettings);
	$("#statsPanel").classList.toggle("hidden", isSettings);
	$("#panelTitle").textContent = t(isSettings ? "settings" : "stats");
	$("#panelEyebrow").textContent = isSettings ? t("caregivers") : t("allTime");
	pauseSession();
	updateStats();
	updateEndSessionButton();
	$("#sidePanel").classList.add("open");
	$("#sidePanel").setAttribute("aria-hidden", "false");
	$("#scrim").classList.add("show");
	$("#closePanel").focus();
}

/** Hides the side panel and its scrim, and resumes a paused session's clock. */
function closePanel() {
	$("#sidePanel").classList.remove("open");
	$("#sidePanel").setAttribute("aria-hidden", "true");
	$("#scrim").classList.remove("show");
	resumeSession();
}

/**
 * Reveals the update banner. The first click on "Update now" disables the
 * button and invokes `applyUpdate`.
 * @param {() => void} applyUpdate Called when the user confirms the update.
 */
function showUpdateBanner(applyUpdate) {
	$("#updateBanner").classList.remove("hidden");
	$("#updateNowButton").addEventListener(
		"click",
		(event) => {
			event.currentTarget.disabled = true;
			applyUpdate();
		},
		{ once: true },
	);
}

/**
 * Shows the iOS install tip; its dismiss button hides the tip and invokes
 * `onDismiss` once.
 * @param {() => void} onDismiss Called when the user dismisses the tip.
 */
function showIosInstallTip(onDismiss) {
	$("#iosInstallTip").classList.remove("hidden");
	$("#dismissIosTip").addEventListener(
		"click",
		() => {
			$("#iosInstallTip").classList.add("hidden");
			onDismiss();
		},
		{ once: true },
	);
}

/**
 * Shares the session results (presses and best streak): via the Web Share
 * API when present (a dismissed share sheet is ignored), otherwise by
 * copying text and URL to the clipboard and briefly swapping the share
 * button label to a confirmation. Does nothing when neither is available.
 */
async function shareSessionResults() {
	const text = t("shareText")
		.replace("{presses}", state.sessionPresses)
		.replace("{streak}", state.bestStreak);
	const shareData = { title: "Magic Smash", text, url: window.location.href };

	if (navigator.share) {
		try {
			await navigator.share(shareData);
		} catch {
			/* The user closing the share sheet isn't a failure to react to. */
		}
		return;
	}

	if (!navigator.clipboard) return;
	try {
		await navigator.clipboard.writeText(`${text} ${shareData.url}`);
		const label = $("#shareButton").querySelector("[data-i18n]");
		const original = label.textContent;
		label.textContent = t("linkCopied");
		setTimeout(() => {
			label.textContent = original;
		}, 2000);
	} catch {
		/* Clipboard access can be denied by the browser; nothing more to try. */
	}
}

